import React from "react";
import { ExplorerHeader } from "components/ExplorerHeader";
import { ExplorerFooter } from "components/ExplorerFooter";
import { DataSource, DataSourceContext } from "schema/DataSource";
import { Parallax } from "react-parallax";
import { ScrollMenu } from "react-horizontal-scrolling-menu";
import { AssetPresentation } from "./AssetPresentation";
import { Box, useTheme } from "@mui/system";
import { Grid, Typography } from "@mui/material";
import { useContext } from "react";
import { useNavigate } from "react-router-dom";

interface ExplorerRenderProps {
  id: number;
  dataSource: DataSource;
}

export const AssetRender: React.FC<ExplorerRenderProps> = ({ id, dataSource }) => (
  <DataSourceContext.Provider value={dataSource}>
    <Parallax>
      <ExplorerHeader id={id} />
      <AssetPresentation id={id} />
      <AssetProperties id={id} />
    </Parallax>
    <ExplorerFooter id={id} />
  </DataSourceContext.Provider>
);

export const CertificateRender: React.FC<ExplorerRenderProps> = ({ id, dataSource }) => (
  <DataSourceContext.Provider value={dataSource}>
    <ExplorerHeader id={id} />
    <ExplorerFooter id={id} />
  </DataSourceContext.Provider>
);

export const TraceabilityRender: React.FC<ExplorerRenderProps> = ({ id, dataSource }) => (
  <DataSourceContext.Provider value={dataSource}>
    <ExplorerHeader id={id} />
    <ExplorerFooter id={id} />
  </DataSourceContext.Provider>
);

export const StatisticsRender: React.FC<ExplorerRenderProps> = ({ id, dataSource }) => (
  <DataSourceContext.Provider value={dataSource}>
    <ExplorerHeader id={id} />
    <ExplorerFooter id={id} />
  </DataSourceContext.Provider>
);

interface AssetPropertiesProps {
  id: number;
}

const AssetParent: React.FC<AssetPropertiesProps> = ({ id }) => {
  const navigate = useNavigate();
  const theme = useTheme();

  const { erc245 } = useContext(DataSourceContext);
  const [asset] = erc245.getAsset(id);

  const handleClick = () => navigate(`/explorer/asset/` + asset.id);
  return (
    <Box
      margin={1.5}
      minWidth={230}
      bgcolor={"white"}
      borderRadius={3}
      p={2.5}
      onClick={handleClick}
      sx={{ boxShadow: "5px 5px 10px -2px rgba(0,0,0,0.1)", cursor: "pointer" }}
    >
      <Grid container direction={"row"} justifyContent={"flex-start"} alignItems={"flex-start"}>
        <Grid item>
          <Box
            width={60}
            height={60}
            borderRadius={3}
            marginRight={2}
            sx={{ backgroundImage: `url(${asset.metadata.image})`, backgroundSize: "cover" }}
          />
        </Grid>
        <Grid item>
          <Grid
            container
            direction="column"
            justifyContent="space-around"
            alignItems="flex-start"
            height={60}
          >
            <Typography variant="caption" lineHeight={1}>
              {asset.metadata.fabricator}
            </Typography>
            <Typography variant="h5" lineHeight={1}>
              {asset.name}
            </Typography>
            <Typography
              color={theme.palette.primary.main}
              fontSize={20}
              fontWeight={"bold"}
              lineHeight={1}
            >
              {asset.co2} (CO2e)
            </Typography>
          </Grid>
        </Grid>
      </Grid>
    </Box>
  );
};

const AssetProperties: React.FC<AssetPropertiesProps> = ({ id }) => {
  const { erc245 } = useContext(DataSourceContext);
  const [[parents]] = erc245.getAssetComposition(id);

  return (
    <>
      <Typography variant="h4" marginLeft={3} marginTop={3} sx={{ opacity: 0.5 }}>
        Composition
      </Typography>
      <ScrollMenu>
        {parents.map((p) => (
          <AssetParent id={p} key={p} />
        ))}
      </ScrollMenu>
    </>
  );
};
