import { Box, Grid } from "@mui/material";
import React, { useContext } from "react";
import CropFreeRoundedIcon from "@mui/icons-material/CropFreeRounded";
import VerifiedUserRoundedIcon from "@mui/icons-material/VerifiedUserRounded";
import TimelineRoundedIcon from "@mui/icons-material/TimelineRounded";
import BarChartRoundedIcon from "@mui/icons-material/BarChartRounded";
import FeedRoundedIcon from "@mui/icons-material/FeedRounded";
import { DataSourceContext } from "schema/DataSource";
import { IconButton } from "@mui/material";
import { useLocation, useNavigate } from "react-router-dom";
import { Button } from "./Button";

interface NavButtonProps {
  path: string;
  text: string;
  active?: boolean;
}
export const NavButton: React.FC<NavButtonProps> = ({ active, path, text, children }) => {
  const navigate = useNavigate();
  const location = useLocation();

  if (active || location.pathname.includes(text.toLowerCase()))
    return (
      <Button startIcon={children} variant="contained" size="large" color="secondary">
        {text}
      </Button>
    );

  return (
    <IconButton color="inherit" onClick={() => navigate(path)}>
      {children}
    </IconButton>
  );
};

interface ExplorerFooterProps {
  id: number;
}

export const ExplorerFooter: React.FC<ExplorerFooterProps> = ({ id }) => {
  const { erc245 } = useContext(DataSourceContext);
  const [asset] = erc245.getAsset(id);

  return (
    <>
      <Box sx={{ height: 56, width: "100%" }} />
      <Box
        p={1}
        bgcolor={"white"}
        sx={{
          boxShadow: "0px -5px 30px 0px rgba(200,200,200,0.5)",
          width: "100%",
          position: "absolute",
          bottom: 0,
          borderRadius: 15,
        }}
      >
        <Grid container justifyContent={"space-evenly"} alignItems={"center"} color={"#D5DAE1"}>
          <NavButton text="Asset" path={`/explorer/asset/` + asset.id}>
            <FeedRoundedIcon sx={{ cursor: "pointer" }} />
          </NavButton>
          <NavButton text="Certificate" path={`/explorer/certificate/` + asset.cert}>
            <VerifiedUserRoundedIcon sx={{ cursor: "pointer" }} />
          </NavButton>
          <NavButton text="Traceability" path={`/explorer/traceability/` + asset.id}>
            <TimelineRoundedIcon sx={{ cursor: "pointer" }} />
          </NavButton>
          <NavButton text="Statistics" path={`/explorer/statistics/` + asset.id}>
            <BarChartRoundedIcon sx={{ cursor: "pointer" }} />
          </NavButton>
          <NavButton text="QRCode" path={`/explorer`}>
            <CropFreeRoundedIcon />
          </NavButton>
        </Grid>
      </Box>
    </>
  );
};
