import { HashRouter as Router, Route, Routes, Navigate } from "react-router-dom";
import {
  ExplorerScanner,
  ExplorerAssetView,
  ExplorerCertificateView,
  ExplorerTraceabilityView,
  ExplorerStatisticsView,
} from "./pages/Explorer";

export const AppRoutes = () => {
  return (
    <Router>
      <Routes>
        <Route path="/explorer/" element={<ExplorerScanner />} />
        <Route path="/explorer/asset/:id" element={<ExplorerAssetView />} />
        <Route path="/explorer/certificate/:id" element={<ExplorerCertificateView />} />
        <Route path="/explorer/traceability/:id" element={<ExplorerTraceabilityView />} />
        <Route path="/explorer/statistics/:id" element={<ExplorerStatisticsView />} />
        <Route path="*" element={<NoMatch />} />
      </Routes>
    </Router>
  );
};

const NoMatch = () => <Navigate to="/explorer" />;
